                <Btn full outline color="#a78bfa" onClick={() => setEditing(true)}>✏️ Editar</Btn>
                <Btn full onClick={() => {
                  const dias = diasParaVencer(m.vence);
                  // If still active (not expired), suggest renewing from current vence date
                  // Otherwise suggest today
                  const venceISO = (() => {
                    const v = parseDate(m.vence);
                    if (!v) return todayISO();
                    const d = v; d.setHours(0,0,0,0);
                    return d.toISOString().split("T")[0];
                  })();
                  const sugerido = (dias !== null && dias > 0) ? venceISO : todayISO();
                  setRenovar({ plan: m.plan, monto: String(m.monto), inicio: sugerido, vence: calcVence(sugerido, m.plan) });
