                {t.tipo === "ingreso" ? "+" : "-"}{fmt(t.monto)}
              </p>
            </div>
          ))}

          {pagoModal && (
            <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.82)", backdropFilter: "blur(8px)", zIndex: 200, display: "flex", alignItems: "flex-end" }}>
